import { GoogleGenAI, Type } from "@google/genai";
import { RoadmapResponse } from "../types";

const getClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const FLASH_MODEL = 'gemini-3-flash-preview';
const PRO_MODEL = 'gemini-3-pro-preview';

// System Instruction for all legal tasks to ensure 2026 context
const SYSTEM_INSTRUCTION_2026 = `
Bạn là "Bố 3 Con" - Chuyên gia Pháp lý và Tài chính cá nhân hàng đầu tại Việt Nam.
KIẾN THỨC CẬP NHẬT: Bạn nắm vững toàn bộ các thay đổi trong Luật Các tổ chức tín dụng (sửa đổi), Luật Bảo vệ quyền lợi người tiêu dùng 2023, và các thông tư mới nhất của Ngân hàng Nhà nước có hiệu lực đến năm 2026.
PHONG CÁCH: Lạc quan, kiên định, chuyên nghiệp, bảo vệ quyền lợi con nợ trước các hành vi thu nợ trái luật.
QUY TẮC: Luôn trích dẫn căn cứ pháp lý rõ ràng. Nếu có sự thay đổi luật vào năm 2024-2025, hãy ưu tiên áp dụng quy định mới nhất.
`;

// 1. Legal Document Generator
export const generateLegalDoc = async (type: string, details: string): Promise<string> => {
  const ai = getClient();
  const prompt = `Hãy soạn thảo văn bản: "${type}" dựa trên thông tin: "${details}". Đảm bảo ngôn ngữ chuẩn 2026.`;

  const response = await ai.models.generateContent({
    model: PRO_MODEL,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION_2026 + " Tập trung vào việc soạn thảo văn bản hành chính chuẩn mực.",
      thinkingConfig: { thinkingBudget: 15000 }
    }
  });

  return response.text || "Không thể tạo văn bản lúc này.";
};

// 2. Document Decoder
export const decodeDocument = async (text: string): Promise<string> => {
  const ai = getClient();
  const prompt = `Phân tích và giải mã văn bản/tin nhắn sau theo ngôn ngữ bình dân: "${text}"`;

  const response = await ai.models.generateContent({
    model: PRO_MODEL,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION_2026 + " Nhiệm vụ của bạn là bóc tách các thuật ngữ 'hù dọa' và chỉ ra điểm sai luật của bên đòi nợ.",
      thinkingConfig: { thinkingBudget: 10000 }
    }
  });

  return response.text || "Không thể phân tích văn bản này.";
};

// 3. Response Simulator
export const simulateResponse = async (threat: string): Promise<string> => {
  const ai = getClient();
  const prompt = `Bên đòi nợ đe dọa: "${threat}". Hãy soạn kịch bản phản hồi đanh thép, đúng luật.`;

  const response = await ai.models.generateContent({
    model: PRO_MODEL,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION_2026 + " Tạo kịch bản đối thoại trực tiếp hoặc tin nhắn phản hồi để ngăn chặn quấy rối.",
      thinkingConfig: { thinkingBudget: 8000 }
    }
  });

  return response.text || "Không thể tạo phản hồi lúc này.";
};

// 4. Financial Roadmap
export const generateRoadmap = async (income: number, debt: number, expenses: number): Promise<RoadmapResponse> => {
  const ai = getClient();
  const prompt = `Thu nhập: ${income}tr, Nợ: ${debt}tr, Sinh hoạt: ${expenses}tr. Lập lộ trình 6 tháng.`;

  const response = await ai.models.generateContent({
    model: PRO_MODEL,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION_2026 + " Lập kế hoạch tài chính thực tế, ưu tiên trả nợ có lãi suất cao nhất hoặc nợ có rủi ro pháp lý lớn nhất.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          analysis: { type: Type.STRING },
          data: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                month: { type: Type.STRING },
                remainingDebt: { type: Type.NUMBER },
                savings: { type: Type.NUMBER },
                note: { type: Type.STRING }
              },
              required: ["month", "remainingDebt", "savings", "note"]
            }
          }
        },
        required: ["analysis", "data"]
      }
    }
  });

  const jsonText = response.text;
  if (!jsonText) throw new Error("No data returned");
  return JSON.parse(jsonText) as RoadmapResponse;
};

// 5. AI Advisor (Chat with Search)
export const chatWithAdvisor = async (message: string, history: {role: string, parts: {text: string}[]}[]): Promise<{text: string, sources: any[]}> => {
  const ai = getClient();

  const response = await ai.models.generateContent({
    model: PRO_MODEL, // Upgrading advisor to Pro for 2026 reasoning
    contents: [
      ...history.map(h => ({ role: h.role, parts: h.parts })),
      { role: 'user', parts: [{ text: message }] }
    ],
    config: {
      tools: [{ googleSearch: {} }],
      systemInstruction: SYSTEM_INSTRUCTION_2026 + " Bạn là người đồng hành đáng tin cậy. Hãy dùng Google Search để cập nhật các án lệ hoặc quy định mới nhất trong tháng này."
    }
  });

  const text = response.text || "Tôi chưa tìm được thông tin chính xác nhất cho bạn.";
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((c: any) => c.web).filter((w: any) => w) || [];

  return { text, sources };
};

// 6. Insolvency Support
export const generateInsolvencySupport = async (reason: string, currentStatus: string): Promise<string> => {
  const ai = getClient();
  const prompt = `Lý do: ${reason}. Tình trạng: ${currentStatus}. Soạn đơn thông báo mất khả năng thanh toán chuẩn 2026.`;

  const response = await ai.models.generateContent({
    model: PRO_MODEL,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION_2026 + " Văn bản này rất quan trọng để xác lập tình trạng dân sự, giúp tránh bị truy cứu trách nhiệm hình sự về tội lừa đảo/lạm dụng tín nhiệm.",
      thinkingConfig: { thinkingBudget: 20000 }
    }
  });

  return response.text || "Không thể tạo nội dung lúc này.";
};

