export default Layout;

import React, { useState } from 'react';
import { generateLegalDoc } from '../services/geminiService';
import { FileText, Loader2, Copy, Check, Info, FileSearch } from 'lucide-react';

const LegalDocGenerator: React.FC = () => {
  const [docType, setDocType] = useState('Đơn đề nghị giãn nợ');
  const [details, setDetails] = useState('');
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleGenerate = async () => {
    if (!details.trim()) return;
    setLoading(true);
    setCopied(false);
    try {
      const text = await generateLegalDoc(docType, details);
      setResult(text);
    } catch (error) {
      console.error(error);
      setResult("Có lỗi xảy ra, vui lòng thử lại.");
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(result);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-fade-in-up">
      <div className="text-center">
        <h1 className="text-3xl font-extrabold text-slate-900 mb-2">Soạn Văn Bản Pháp Lý 2026</h1>
        <p className="text-slate-500">Tạo văn bản chuyên nghiệp chỉ với vài thông tin cơ bản.</p>
      </div>

      <div className="grid md:grid-cols-12 gap-8">
        {/* Input Panel */}
        <div className="md:col-span-5 space-y-6">
          <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm">
            <div className="space-y-6">
              <div>
                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-3">Loại văn bản mẫu</label>
                <div className="grid grid-cols-1 gap-2">
                  {[
                    "Đơn đề nghị giãn nợ",
                    "Đơn tố giác đòi nợ thuê trái luật",
                    "Đơn đề nghị miễn giảm lãi phạt",
                    "Đơn tố giác bôi nhọ danh dự"
                  ].map(type => (
                    <button
                      key={type}
                      onClick={() => setDocType(type)}
                      className={`text-left px-4 py-3 rounded-xl border text-sm transition-all ${
                        docType === type 
                        ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-200' 
                        : 'bg-slate-50 border-slate-200 text-slate-600 hover:border-blue-300'
                      }`}
                    >
                      {type}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-3">Thông tin chi tiết</label>
                <textarea 
                  value={details}
                  onChange={(e) => setDetails(e.target.value)}
                  rows={8}
                  placeholder="Họ tên, ngân hàng, số tiền nợ, lý do khó khăn, hoặc hành vi bị đe dọa..."
                  className="w-full rounded-2xl border-slate-200 border p-4 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 text-sm bg-slate-50 transition-all"
                ></textarea>
              </div>

              <button 
                onClick={handleGenerate}
                disabled={loading || !details}
                className="w-full py-4 bg-blue-600 hover:bg-blue-700 disabled:bg-slate-300 text-white font-bold rounded-2xl transition-all shadow-xl shadow-blue-500/20 flex items-center justify-center gap-2 active:scale-95"
              >
                {loading ? <Loader2 className="animate-spin w-5 h-5" /> : "Soạn văn bản ngay"}
              </button>
            </div>
          </div>

          <div className="bg-blue-50 p-6 rounded-[1.5rem] border border-blue-100 flex items-start space-x-3">
            <Info className="w-5 h-5 text-blue-600 shrink-0 mt-0.5" />
            <p className="text-xs text-blue-800 leading-relaxed">
              Hệ thống sẽ tự động chèn các điều luật dân sự và thông tư NHNN mới nhất 2026 vào văn bản để đảm bảo tính pháp lý cao nhất.
            </p>
          </div>
        </div>

        {/* Preview Panel */}
        <div className="md:col-span-7">
          <div className="bg-slate-900 rounded-[2rem] p-8 md:p-12 shadow-2xl relative min-h-[600px] flex flex-col">
            <div className="flex justify-between items-center mb-8">
              <div className="flex items-center space-x-2 text-slate-400">
                <FileSearch className="w-4 h-4" />
                <span className="text-xs font-bold uppercase tracking-widest">Bản thảo AI</span>
              </div>
              {result && (
                <button 
                  onClick={copyToClipboard}
                  className="flex items-center space-x-2 bg-white/10 hover:bg-white/20 text-white px-4 py-2 rounded-xl transition-all text-xs font-bold"
                >
                  {copied ? <><Check className="w-4 h-4" /> <span>Đã sao chép</span></> : <><Copy className="w-4 h-4" /> <span>Sao chép</span></>}
                </button>
              )}
            </div>

            <div className="flex-grow overflow-y-auto">
              {result ? (
                <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap font-serif leading-relaxed text-slate-200">
                  {result}
                </div>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-600 space-y-4">
                  <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mb-4">
                    <FileText className="w-10 h-10 opacity-20" />
                  </div>
                  <p className="text-sm font-medium">Nhập thông tin bên trái để bắt đầu soạn thảo</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

