export const chatWithAdvisor = async (message: string, history: {role: string, parts: {text: string}[]}[]): Promise<{text: string, sources: any[]}> => {
  const ai = getClient();

  const response = await ai.models.generateContent({
    model: PRO_MODEL,
    contents: [
      ...history.map(h => ({ role: h.role, parts: h.parts })),
      { role: 'user', parts: [{ text: message }] }
    ],
    config: {
      tools: [{ googleSearch: {} }],
      systemInstruction: SYSTEM_INSTRUCTION_2026 + " Bạn phải cập nhật thông tin về các vụ án hình sự liên quan đến 'cưỡng đoạt tài sản' núp bóng thu hồi nợ trong năm 2025-2026 để làm dẫn chứng thực tế cho người dùng."
    }
  });

  const text = response.text || "Tôi chưa tìm được thông tin chính xác nhất cho bạn theo luật 2026.";
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((c: any) => c.web).filter((w: any) => w) || [];

  return { text, sources };
};

// 6. Insolvency Support
export const generateInsolvencySupport = async (reason: string, currentStatus: string): Promise<string> => {
  const ai = getClient();
  const prompt = `Lý do: ${reason}. Tình trạng: ${currentStatus}. Soạn văn bản 'Thông báo xác lập tình trạng mất khả năng thanh toán tạm thời' theo chuẩn pháp lý 2026.`;

  const response = await ai.models.generateContent({
    model: PRO_MODEL,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION_2026 + " Văn bản cần dẫn chiếu quy định về việc miễn giảm lãi phạt do biến cố bất khả kháng theo Bộ luật Dân sự và các quy định bổ sung 2026.",
      thinkingConfig: { thinkingBudget: 20000 }
    }
  });

  return response.text || "Không thể tạo nội dung lúc này.";
}

