// 1. Legal Document Generator
export const generateLegalDoc = async (type: string, details: string): Promise<string> => {
  const ai = getClient();
  const prompt = `Hãy soạn thảo văn bản: "${type}" dựa trên thông tin: "${details}". Văn bản phải tuân thủ nghiêm ngặt thể thức hành chính 2026 và tích hợp các căn cứ pháp lý về bảo vệ dữ liệu cá nhân để chống quấy rối.`;

  const response = await ai.models.generateContent({
    model: PRO_MODEL,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION_2026 + " Tập trung vào việc soạn thảo văn bản có tính răn đe pháp lý cao đối với các đơn vị thu hồi nợ sai luật.",
      thinkingConfig: { thinkingBudget: 15000 }
    }
  });

  return response.text || "Không thể tạo văn bản lúc này.";
};

