export const decodeDocument = async (text: string): Promise<string> => {
  const ai = getClient();
  const prompt = `Phân tích và giải mã văn bản/tin nhắn này theo luật pháp Việt Nam 2026: "${text}". Chỉ ra các điểm vi phạm về bảo vệ dữ liệu cá nhân hoặc quy tắc đạo đức nghề nghiệp ngân hàng.`;

  const response = await ai.models.generateContent({
    model: PRO_MODEL,
    contents: prompt,
