// 4. Financial Roadmap
export const generateRoadmap = async (income: number, debt: number, expenses: number): Promise<RoadmapResponse> => {
  const ai = getClient();
  const prompt = `Thu nhập: ${income}tr, Nợ: ${debt}tr, Sinh hoạt: ${expenses}tr. Lập lộ trình 6 tháng. Tư vấn cách ưu tiên trả nợ dựa trên mức độ rủi ro pháp lý của từng khoản nợ theo luật 2026.`;

  const response = await ai.models.generateContent({
    model: PRO_MODEL,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION_2026 + " Lập kế hoạch tài chính thực tế, tư vấn cả cách bảo vệ nguồn thu nhập khỏi việc quấy rối tại nơi làm việc.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          analysis: { type: Type.STRING },
          data: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                month: { type: Type.STRING },
                remainingDebt: { type: Type.NUMBER },
                savings: { type: Type.NUMBER },
                note: { type: Type.STRING }
              },
              required: ["month", "remainingDebt", "savings", "note"]
            }
          }
        },
        required: ["analysis", "data"]
      }
    }
  });

  const jsonText = response.text;
  if (!jsonText) throw new Error("No data returned");
  return JSON.parse(jsonText) as RoadmapResponse;
};

// 5. AI Advisor (Chat with Search)
export const chatWithAdvisor = async (message: string, history: {role: string, parts: {text: string}[]}[]): Promise<{text: string, sources: any[]}> => {
  const ai = getClient();

  const response = await ai.models.generateContent({
    model: PRO_MODEL,
    contents: [
      ...history.map(h => ({ role: h.role, parts: h.parts })),
      { role: 'user', parts: [{ text: message }] }
    ],
    config: {
      tools: [{ googleSearch: {} }],
      systemInstruction: SYSTEM_INSTRUCTION_2026 + " Bạn phải cập nhật thông tin về các vụ án hình sự liên quan đến 'cưỡng đoạt tài sản' núp bóng thu hồi nợ trong năm 2025-2026 để làm dẫn chứng thực tế cho người dùng."
    }
  });

  const text = response.text || "Tôi chưa tìm được thông tin chính xác nhất cho bạn theo luật 2026.";
  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((c: any) => c.web).filter((w: any) => w) || [];

  return { text, sources };
};

